	/** Resolved absolute path */
	absolutePath: string;
	/** Link text/label */
	linkText: string;
	/** Source file containing the link */
	sourcePath: string;
}

/**
 * Options for linked docs discovery
 */
export interface IDocDiscoveryOptions {
	/** AI provider for summarization */
	provider: IAIProvider;
	/** Enable verbose logging */
